  "authors": [
   "Özlü Erdoğan Hande",
   "Aras Bayram Gülay",
   "Targıt Akbaşak Sema",
   "Tarakcı Devrim"
  ],
  "journal": "JMIR research protocols",
  "doi": "10.2196/94705",
